export declare const defaultStyles = "\n* {\n    box-sizing: border-box;\n    margin: 0;\n    padding: 0;\n}\n\n:root {\n    --zerp-bg: #0d1117;\n    --zerp-panel: #161b22;\n    --zerp-border: #30363d;\n    --zerp-text: #e6edf3;\n    --zerp-muted: #8b949e;\n    --zerp-faint: #484f58;\n    --zerp-accent: #58a6ff;\n    --zerp-green: #3fb950;\n    --zerp-orange: #f0883e;\n    --zerp-purple: #bc8cff;\n    --zerp-red: #f85149;\n}\n\nhtml,\nbody {\n    width: 100%;\n    height: 100%;\n    overflow: hidden;\n    background: var(--zerp-bg);\n    color: var(--zerp-text);\n    font-family: \"Montserrat\", sans-serif;\n}\n\nimg,\nvideo {\n    max-width: 100%;\n}\n\n.slide {\n    display: none;\n    width: 100vw;\n    height: 100vh;\n    padding: 50px 70px;\n    flex-direction: column;\n    justify-content: center;\n    position: relative;\n}\n\n.slide.active {\n    display: flex;\n}\n\n.slide h1 {\n    font-size: 3.2em;\n    font-weight: 900;\n    line-height: 1.15;\n    margin-bottom: 20px;\n}\n\n.slide h2 {\n    font-size: 2.2em;\n    font-weight: 700;\n    line-height: 1.2;\n    margin-bottom: 14px;\n}\n\n.slide h3 {\n    font-size: 1.4em;\n    font-weight: 700;\n    margin-bottom: 10px;\n    color: var(--zerp-muted);\n}\n\n.slide p,\n.slide li {\n    font-size: 1.25em;\n    line-height: 1.5;\n    color: #c9d1d9;\n}\n\n.slide ul {\n    list-style: none;\n    padding: 0;\n}\n\n.slide li {\n    padding: 5px 0;\n}\n\n.slide li::before {\n    content: \"\u2192 \";\n    color: var(--zerp-accent);\n}\n\n.accent {\n    color: var(--zerp-accent);\n}\n\n.accent-green {\n    color: var(--zerp-green);\n}\n\n.accent-orange {\n    color: var(--zerp-orange);\n}\n\n.accent-purple {\n    color: var(--zerp-purple);\n}\n\n.accent-red {\n    color: var(--zerp-red);\n}\n\n.big-number {\n    font-size: 3em;\n    font-weight: 900;\n    color: var(--zerp-accent);\n    font-family: \"Roboto Mono\", monospace;\n}\n\n.img-row {\n    display: flex;\n    gap: 24px;\n    align-items: center;\n    justify-content: center;\n    margin: 24px 0;\n    flex-wrap: wrap;\n}\n\n.img-row img {\n    max-height: 300px;\n    border-radius: 10px;\n    object-fit: contain;\n    background: var(--zerp-panel);\n    padding: 6px;\n}\n\n.two-col {\n    display: grid;\n    grid-template-columns: 1fr 1fr;\n    gap: 40px;\n    align-items: center;\n}\n\n.caption {\n    font-size: 0.8em;\n    color: var(--zerp-muted);\n    text-align: center;\n    margin-top: 4px;\n}\n\n.block-label {\n    position: absolute;\n    top: 24px;\n    left: 70px;\n    font-size: 0.8em;\n    font-weight: 700;\n    color: var(--zerp-faint);\n    text-transform: uppercase;\n    letter-spacing: 3px;\n}\n\n.interactive-badge {\n    display: inline-block;\n    background: #238636;\n    color: white;\n    padding: 5px 16px;\n    border-radius: 20px;\n    font-size: 0.8em;\n    font-weight: 700;\n    margin-bottom: 14px;\n}\n\n.timeline {\n    display: flex;\n    gap: 20px;\n    flex-wrap: wrap;\n    justify-content: center;\n    margin: 16px 0;\n}\n\n.timeline .item {\n    background: var(--zerp-panel);\n    border: 1px solid var(--zerp-border);\n    border-radius: 10px;\n    padding: 14px 18px;\n    text-align: center;\n    min-width: 130px;\n}\n\n.timeline .item .year {\n    font-family: \"Roboto Mono\", monospace;\n    font-size: 1.3em;\n    font-weight: 700;\n    color: var(--zerp-accent);\n}\n\n.timeline .item .label {\n    font-size: 0.85em;\n    color: #c9d1d9;\n    margin-top: 4px;\n}\n\n.nav {\n    position: fixed;\n    bottom: 24px;\n    right: 36px;\n    display: flex;\n    gap: 10px;\n    z-index: 100;\n}\n\n.nav button {\n    background: none;\n    border: none;\n    color: var(--zerp-faint);\n    padding: 4px 8px;\n    cursor: pointer;\n    font-size: 0.85em;\n    font-family: \"Roboto Mono\", monospace;\n}\n\n.nav button:hover {\n    color: var(--zerp-muted);\n}\n\n.counter {\n    position: fixed;\n    bottom: 28px;\n    left: 36px;\n    font-size: 0.85em;\n    color: var(--zerp-faint);\n    font-family: \"Roboto Mono\", monospace;\n    z-index: 100;\n}\n\n.progress {\n    position: fixed;\n    top: 0;\n    left: 0;\n    height: 3px;\n    background: var(--zerp-accent);\n    z-index: 100;\n    transition: width 0.3s;\n}\n\n.quote {\n    border-left: 4px solid var(--zerp-accent);\n    padding: 14px 20px;\n    margin: 16px 0;\n    background: var(--zerp-panel);\n    border-radius: 0 10px 10px 0;\n    font-style: italic;\n    font-size: 1.1em;\n}\n\n.key-thought {\n    background: var(--zerp-panel);\n    border: 2px solid var(--zerp-accent);\n    border-radius: 14px;\n    padding: 28px 36px;\n    margin: 16px 0;\n    text-align: center;\n}\n\n.key-thought p {\n    font-size: 1.4em;\n    font-weight: 700;\n    color: var(--zerp-text);\n}\n\n.grid-demo {\n    display: grid;\n    grid-template-columns: repeat(7, 48px);\n    gap: 3px;\n    justify-content: center;\n    margin: 16px 0;\n}\n\n.grid-demo .cell {\n    width: 48px;\n    height: 48px;\n    border: 2px solid var(--zerp-border);\n    border-radius: 5px;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    font-size: 0.75em;\n    color: var(--zerp-faint);\n}\n\n.grid-demo .cell.filled {\n    background: var(--zerp-red);\n    border-color: var(--zerp-red);\n    color: white;\n}\n";
export declare const defaultRuntime = "\n(() => {\n    const slides = Array.from(document.querySelectorAll(\".slide\"));\n    let current = 0;\n    const total = slides.length;\n    const counter = document.getElementById(\"counter\");\n    const progress = document.getElementById(\"progress\");\n\n    function clamp(index) {\n        return Math.max(0, Math.min(index, total - 1));\n    }\n\n    function show(index) {\n        current = clamp(index);\n        for (const slide of slides) {\n            slide.classList.remove(\"active\");\n        }\n        const active = slides[current];\n        if (!active) {\n            return;\n        }\n        active.classList.add(\"active\");\n        if (counter) {\n            counter.textContent = String(current + 1) + \" / \" + String(total);\n        }\n        if (progress) {\n            progress.style.width = String(((current + 1) / Math.max(total, 1)) * 100) + \"%\";\n        }\n        history.replaceState(null, \"\", \"#\" + String(current + 1));\n    }\n\n    function next() {\n        show(current + 1);\n    }\n\n    function prev() {\n        show(current - 1);\n    }\n\n    function stepForward() {\n        slides[current]?.dispatchEvent(new Event(\"slide-next\"));\n    }\n\n    function stepBackward() {\n        slides[current]?.dispatchEvent(new Event(\"slide-prev\"));\n    }\n\n    window.next = next;\n    window.prev = prev;\n\n    document.addEventListener(\"keydown\", (event) => {\n        if (event.key === \"ArrowRight\" || event.key === \" \" || event.key === \"PageDown\") {\n            event.preventDefault();\n            next();\n        }\n        if (event.key === \"ArrowLeft\" || event.key === \"PageUp\") {\n            event.preventDefault();\n            prev();\n        }\n        if (event.key === \"Home\") {\n            event.preventDefault();\n            show(0);\n        }\n        if (event.key === \"End\") {\n            event.preventDefault();\n            show(total - 1);\n        }\n        if (event.key === \"ArrowDown\") {\n            event.preventDefault();\n            stepForward();\n        }\n        if (event.key === \"ArrowUp\") {\n            event.preventDefault();\n            stepBackward();\n        }\n    });\n\n    let touchStartX = 0;\n    document.addEventListener(\"touchstart\", (event) => {\n        touchStartX = event.touches[0]?.clientX ?? 0;\n    });\n    document.addEventListener(\"touchend\", (event) => {\n        const delta = touchStartX - (event.changedTouches[0]?.clientX ?? 0);\n        if (Math.abs(delta) > 60) {\n            delta > 0 ? next() : prev();\n        }\n    });\n\n    show((Number.parseInt(location.hash.slice(1), 10) || 1) - 1);\n})();\n";
